INSERT INTO edges (edge_id, slug, title, category, status, hypothesis, rationale, counter_evidence, evidence, origin, pdf_ref, priors, created_at, updated_at)
VALUES ('01KWHQ6YVN5931C774810HDR72', 'order-flow-imbalance-ofi-mid-price-prediction', 'オーダーフローインバランス(OFI)によるミッド価格予測', 'microstructure', 'IDEA', 'Binance無期限先物の板最良気配におけるOFI(オーダーフローインバランス)が1〜5分間で、ミッド価格を同方向に動かす。', 'OFIはマーケットメイカーが再クォート前に吸収せざるを得ない片側圧力を反映しており、短期的な方向性ドリフトを生む。', '先物ミッド価格と現物板インバランスの相関(0.94)で示されているのみで、ウォークフォワード検証は行われていない。', '[{"kind":"paper","ref":"arXiv:2602.00776","note":"暗号資産マイクロストラクチャーにおける説明可能なパターン"}]', 'pdf_seed', 'EC-001', '{"originality":3,"feasibility":2,"verifiability":3,"lowCost":2,"dataEase":4,"durability":3,"humanOps":2}', 1782950400000, 1782950400000);

INSERT INTO edges (edge_id, slug, title, category, status, hypothesis, rationale, counter_evidence, evidence, origin, pdf_ref, priors, created_at, updated_at)
VALUES ('01KWHQ6YVPQASVA4CQSV1F6V7Q', 'vpin-based-jump-prediction', 'VPINに基づくジャンプ予測', 'microstructure', 'IDEA', 'VPIN(オーダーフロー毒性)の上昇は、正の系列相関を伴って価格ジャンプに先行する。', '情報優位トレーダーの注文フローは、流動性提供者が再プライシングする前に蓄積するため、毒性指標は実現ジャンプに先行する。', 'VPINのボリュームバケット化パラメータ設定は、事後研究におけるルックアヘッド/過学習リスクの既知の原因である。', '[{"kind":"paper","ref":"ScienceDirect S0275531925004192","note":"VPINは将来の価格ジャンプを有意に予測する"}]', 'pdf_seed', 'EC-002', '{"originality":4,"feasibility":3,"verifiability":3,"lowCost":3,"dataEase":4,"durability":3,"humanOps":3}', 1782950400000, 1782950400000);

INSERT INTO edges (edge_id, slug, title, category, status, hypothesis, rationale, counter_evidence, evidence, origin, pdf_ref, priors, created_at, updated_at)
VALUES ('01KWHQ6YVPHWYTNG1SFVDAZ8HS', 'cross-exchange-ofi-lead-lag-coinbase-binance', '取引所間OFIのリード・ラグ関係(Coinbase→Binance)', 'microstructure', 'IDEA', 'Coinbaseの現物注文フローは、Binance先物の注文フローに数秒先行する。', 'Coinbaseは米国時間帯に流動性が集中するため、裁定取引がギャップを埋める前に、そのフローがBinanceのグローバル先物市場に影響を与える。', 'これほど短いリード・ラグの時間窓は取引所のレイテンシに極めて敏感であり、データ収集時点から効果が減衰している可能性がある。', '[{"kind":"internal","ref":"Granger causality analysis","note":"Coinbase対BinanceのOFI、秒足ティックデータ"}]', 'pdf_seed', 'EC-003', '{"originality":4,"feasibility":2,"verifiability":3,"lowCost":3,"dataEase":3,"durability":3,"humanOps":2}', 1782950400000, 1782950400000);

INSERT INTO edges (edge_id, slug, title, category, status, hypothesis, rationale, counter_evidence, evidence, origin, pdf_ref, priors, created_at, updated_at)
VALUES ('01KWHQ6YVPJQMMNN73Z2P4J6D7', 'order-book-depth-regression-on-spread-returns', '板の厚みによるスプレッドリターン回帰', 'microstructure', 'IDEA', 'Binanceの板厚みインバランス回帰は、非常に短期のスプレッドリターンを予測する。', 'マーケットメイカーの在庫の偏りは、約定に現れる前に板の厚みに現れる。', '回帰係数の統計的有意性はまだ確立されていない。', '[{"kind":"internal","ref":"Binance depth snapshots","note":"スプレッドZスコア回帰"}]', 'pdf_seed', 'EC-004', '{"originality":2,"feasibility":3,"verifiability":3,"lowCost":3,"dataEase":4,"durability":2,"humanOps":3}', 1782950400000, 1782950400000);

INSERT INTO edges (edge_id, slug, title, category, status, hypothesis, rationale, counter_evidence, evidence, origin, pdf_ref, priors, created_at, updated_at)
VALUES ('01KWHQ6YVPWGSY9SYV7J2NY1QP', 'cvd-price-divergence', 'CVD(累積ボリュームデルタ)/価格ダイバージェンス', 'microstructure', 'IDEA', '累積ボリュームデルタ(CVD)が価格から乖離する(デルタ上昇・価格横ばいまたは下落)状態は、反転に先行する。', '価格に反映されない持続的な片側テイカーの攻勢は、いずれ崩れる受動的吸収を示唆する。', 'CVDの絶対水準は非定常であり、ダイバージェンス検出は選択した正規化ウィンドウに敏感である。', '[{"kind":"internal","ref":"Binance aggTrades CVD","note":"ダイバージェンス検出ヒューリスティック"}]', 'pdf_seed', 'EC-005', '{"originality":3,"feasibility":3,"verifiability":3,"lowCost":3,"dataEase":4,"durability":3,"humanOps":3}', 1782950400000, 1782950400000);

INSERT INTO edges (edge_id, slug, title, category, status, hypothesis, rationale, counter_evidence, evidence, origin, pdf_ref, priors, created_at, updated_at)
VALUES ('01KWHQ6YVPEWYP4FNKH0C0W8EV', 'liquidation-cascade-rebound', '清算カスケード後のリバウンド', 'liquidation', 'IDEA', '24時間清算Zスコアの急上昇がOI(建玉)の減少と同時に発生した後、BTCはその後24〜72時間でリバウンドする。', '清算は価格非感応的な強制売買であり、デレバレッジが尽きると価格は適正価値に向けて反発する(Brunnermeier & Pedersenの流動性スパイラル理論)。', 'Binanceの強制決済(forceOrder)フィードは2021年以降のサンプリングストリームであり完全な記録ではないため、規模の推定値は概算に留まる。', '[{"kind":"paper","ref":"SSRN 5611392","note":"2025年10月のカスケード分析、GARCH alpha+beta ≈ 0.90"}]', 'pdf_seed', 'EC-006', '{"originality":4,"feasibility":4,"verifiability":3,"lowCost":3,"dataEase":3,"durability":4,"humanOps":4}', 1782950400000, 1782950400000);
