INSERT INTO edges (edge_id, slug, title, category, status, hypothesis, rationale, counter_evidence, evidence, origin, pdf_ref, priors, created_at, updated_at)
VALUES ('01KWHQ6YVPQCXPECAKG0HEMX44', 'funding-rate-mean-reversion', '資金調達率の平均回帰', 'liquidation', 'IDEA', '極端な資金調達率(上下パーセンタイル)は、その後8〜72時間で平均回帰する。', '過度に混雑したレバレッジポジションは、資金調達コストが方向性への確信を上回った時点で自壊的になる。', '引用されている効果量は小さく(beta ≈ -0.087、R^2 ≈ 0.003)、分散の大部分は説明されていない。', '[{"kind":"internal","ref":"Fulgur Ventures / SSRN 5576424","note":"BitMEXの資金調達率→その後8時間のBTCリターン"}]', 'pdf_seed', 'EC-007', '{"originality":2,"feasibility":4,"verifiability":4,"lowCost":3,"dataEase":5,"durability":3,"humanOps":4}', 1782950400000, 1782950400000);

INSERT INTO edges (edge_id, slug, title, category, status, hypothesis, rationale, counter_evidence, evidence, origin, pdf_ref, priors, created_at, updated_at)
VALUES ('01KWHQ6YVPCAY5C32SPXNVVY67', 'liquidation-heatmap-magnet', '清算ヒートマップの磁力効果', 'liquidation', 'IDEA', '価格はセッション内で清算が密集する価格帯へ引き寄せられる。', 'マーケットメイカーや流動性ハンターには、近隣のストップ/清算クラスターを発動させ、価格をそこへ引き寄せるインセンティブがある。', '正確なヒートマップの粒度には有料のCoinGlassデータが必要であり、無料プランでの近似は粗い。', '[{"kind":"internal","ref":"CoinGlass heatmap construction","note":"OI(建玉)+清算距離"}]', 'pdf_seed', 'EC-008', '{"originality":4,"feasibility":3,"verifiability":2,"lowCost":2,"dataEase":3,"durability":3,"humanOps":3}', 1782950400000, 1782950400000);

INSERT INTO edges (edge_id, slug, title, category, status, hypothesis, rationale, counter_evidence, evidence, origin, pdf_ref, priors, created_at, updated_at)
VALUES ('01KWHQ6YVP1MYCEBR6P8MR7B05', 'open-interest-price-divergence', '建玉(OI)/価格ダイバージェンス', 'liquidation', 'IDEA', '価格上昇中にOIが減少する(新規ロングでなくショートカバー)場合、価格とOIが共に上昇する場合と比べて、より弱く持続性の低い上昇となる。', '新規資金主導の上昇(OI増加)は新たな確信を反映するが、カバー主導の上昇はショートが解消されると燃料切れになる。', '上昇の「質」を事後的に分類することは、リアルタイムで因果的に識別するより容易である。', '[{"kind":"internal","ref":"Binance OI + CoinGlass","note":"OI/リターン ダイバージェンス分類"}]', 'pdf_seed', 'EC-009', '{"originality":3,"feasibility":4,"verifiability":4,"lowCost":3,"dataEase":4,"durability":3,"humanOps":4}', 1782950400000, 1782950400000);

INSERT INTO edges (edge_id, slug, title, category, status, hypothesis, rationale, counter_evidence, evidence, origin, pdf_ref, priors, created_at, updated_at)
VALUES ('01KWHQ6YVQH3VA2NDGJKY5HC6Z', 'three-exchange-basis-convergence', '3取引所間ベーシスの収束', 'liquidation', 'IDEA', 'Binance/OKX/Deribitの先物ベーシスが閾値を超えて乖離した場合、数日〜数週間以内に収束する。', 'ベーシスは総体的な投機的センチメントの代理指標であり、取引所間裁定によって持続的に乖離できる幅には限界がある。', 'CMEベーシスの正常化(CF Benchmarksによれば2024年の25%から2025年にはほぼゼロへ)は、過去の関係性がレジーム依存である可能性を示唆する。', '[{"kind":"internal","ref":"CF Benchmarks basis series","note":"取引所間ベーシス収束"}]', 'pdf_seed', 'EC-010', '{"originality":3,"feasibility":3,"verifiability":3,"lowCost":3,"dataEase":4,"durability":3,"humanOps":3}', 1782950400000, 1782950400000);

INSERT INTO edges (edge_id, slug, title, category, status, hypothesis, rationale, counter_evidence, evidence, origin, pdf_ref, priors, created_at, updated_at)
VALUES ('01KWHQ6YVQ6YVC6DG8MCRYKGNG', 'top-trader-long-short-ratio-extremes', '上位トレーダーのロング/ショート比率極値', 'liquidation', 'IDEA', '上位トレーダーのL/S(ロング/ショート)アカウント比率の極値は、反転に先行する。', '「スマートマネー」層でさえ極値では混雑し、混雑したポジションは逆風となる材料に対して脆弱である。', 'アカウント比率指標は規模に関わらずアカウントを均等加重するため、実際の資金ポジションを誤って表す可能性がある。', '[{"kind":"internal","ref":"Binance topLongShortAccountRatio","note":"極値比率での反転"}]', 'pdf_seed', 'EC-011', '{"originality":3,"feasibility":4,"verifiability":4,"lowCost":3,"dataEase":4,"durability":3,"humanOps":4}', 1782950400000, 1782950400000);

INSERT INTO edges (edge_id, slug, title, category, status, hypothesis, rationale, counter_evidence, evidence, origin, pdf_ref, priors, created_at, updated_at)
VALUES ('01KWHQ6YVQHT3N15QVZG0ANNWN', 'funding-settlement-microstructure-pattern', '資金調達決済時のマイクロストラクチャーパターン', 'liquidation', 'IDEA', 'UTC 00:00/08:00/16:00の資金調達決済の直前におけるポジション調整は、予測可能な微細パターンを生む。', 'トレーダーは資金調達の支払いを避けるため、あるいは受け取るために決済直前にポジションを調整し、機械的で反復的なフローを生む。', '1分足粒度での効果量は小さく、取引コストを常に上回るとは限らない。', '[{"kind":"internal","ref":"Binance 1m + fundingRate","note":"決済前後のマイクロストラクチャー"}]', 'pdf_seed', 'EC-012', '{"originality":3,"feasibility":4,"verifiability":4,"lowCost":3,"dataEase":5,"durability":2,"humanOps":4}', 1782950400000, 1782950400000);

INSERT INTO edges (edge_id, slug, title, category, status, hypothesis, rationale, counter_evidence, evidence, origin, pdf_ref, priors, created_at, updated_at)
VALUES ('01KWHQ6YVQWNTEFMGN3A078EGQ', 'variance-risk-premium-vrp-selling', '分散リスクプレミアム(VRP)売り', 'options', 'IDEA', 'Deribitの30日インプライドボラティリティ(DVOL)は実現ボラティリティを恒常的に上回るため、ボラティリティの売りは正の期待値を持つ。', 'オプション買い手からの持続的なヘッジ需要は、株式指数のVRPと同様に、売り手に構造的なプレミアムを支払う。', 'テールリスクは深刻かつ非対称であり、VRP売り戦略はボラティリティ急騰時(2020年3月など)に壊滅的なドローダウンを被る可能性がある。', '[{"kind":"paper","ref":"Amberdata/Deribit Insights","note":"2019年以降、IV(インプライドボラティリティ)がRV(実現ボラティリティ)を上回る頻度は約70%"},{"kind":"paper","ref":"arXiv:2410.15195","note":"BitcoinのVRPはS&P500のVRPを上回る"}]', 'pdf_seed', 'EC-013', '{"originality":4,"feasibility":3,"verifiability":3,"lowCost":3,"dataEase":4,"durability":4,"humanOps":3}', 1782950400000, 1782950400000);

INSERT INTO edges (edge_id, slug, title, category, status, hypothesis, rationale, counter_evidence, evidence, origin, pdf_ref, priors, created_at, updated_at)
VALUES ('01KWHQ6YVR935QGJ073489N38F', '25-delta-skew-as-a-realized-vol-forecaster', '25デルタスキューによる実現ボラティリティ予測', 'options', 'IDEA', 'オプションスキューは週次頻度で次期の実現ボラティリティ(リターンではない)を予測する。', 'スキューは市場のテールヘッジ需要を反映しており、方向性については何も語らなくとも、近い将来の実現変動と相関する。', '同研究では、スキューはボラティリティのみを予測しリターンには予測力がないとされており、方向性判断への利用は誤用となる。', '[{"kind":"paper","ref":"Chen, Deng & Nie 2024, Operations Research Letters","note":"スキューは週次RV(実現ボラティリティ)を予測するが、リターンは予測しない"}]', 'pdf_seed', 'EC-014', '{"originality":4,"feasibility":3,"verifiability":3,"lowCost":3,"dataEase":4,"durability":3,"humanOps":3}', 1782950400000, 1782950400000);

INSERT INTO edges (edge_id, slug, title, category, status, hypothesis, rationale, counter_evidence, evidence, origin, pdf_ref, priors, created_at, updated_at)
VALUES ('01KWHQ6YVRAJ6S0F9DS7FFD854', '25-delta-risk-reversal-selling', '25デルタ・リスクリバーサル売り', 'options', 'IDEA', '25デルタのリスクリバーサルを売る(スキューの符号に応じてコール売り・プット買い、あるいはその逆)ことは、単純なオプションオーバーレイの中で最良のリスク調整後リターンを持つ。', '持続的な片側方向へのヘッジ需要により、VRPと同様のメカニズムでスキューが割高な状態に保たれる。', '元となる結果は2020年3月の「ブラックサーズデー」というテールイベントに支配されている可能性が高く、この外れ値を除外した検証が別途必要である。', '[{"kind":"paper","ref":"Amberdata","note":"リスクリバーサル売りが最良のリスク調整後リターンを持つ"}]', 'pdf_seed', 'EC-015', '{"originality":3,"feasibility":2,"verifiability":2,"lowCost":2,"dataEase":4,"durability":3,"humanOps":2}', 1782950400000, 1782950400000);

INSERT INTO edges (edge_id, slug, title, category, status, hypothesis, rationale, counter_evidence, evidence, origin, pdf_ref, priors, created_at, updated_at)
VALUES ('01KWHQ6YVRT5MN93SS5G40ESG9', 'dealer-gamma-exposure-gex-regime', 'ディーラーガンマエクスポージャー(GEX)レジーム', 'options', 'IDEA', 'ディーラーのガンマポジション(ロング/ショートガンマレジーム)は、ボラティリティの増幅か減衰かを予測する。', 'ショートガンマレジームでは、ディーラーのヘッジは順循環的(上昇を買い、下落を売る)となり値動きを増幅させる。ロングガンマはこれを減衰させる。', 'GEXはモデル化・推定された値であり直接観測できず、プロバイダーによって推定値が大きく異なる場合がある。', '[{"kind":"paper","ref":"Bitfinex Alpha","note":"2026年のディーラーガンマ推定値、ネットで約-143,000 BTC"}]', 'pdf_seed', 'EC-016', '{"originality":5,"feasibility":2,"verifiability":2,"lowCost":3,"dataEase":3,"durability":4,"humanOps":2}', 1782950400000, 1782950400000);

INSERT INTO edges (edge_id, slug, title, category, status, hypothesis, rationale, counter_evidence, evidence, origin, pdf_ref, priors, created_at, updated_at)
VALUES ('01KWHQ6YVRWKX10D9GR41BN0S2', 'options-expiry-sq-max-pain-gravitational-pull', 'オプション満期(SQ)/マックスペインへの引力', 'options', 'IDEA', '大規模なオプション満期前には、価格はマックスペイン(最大の苦痛)行使価格へ向かってドリフトし、ピンリスクが解消されると急反転する場合がある。', '大規模満期付近でのディーラーヘッジフローは、オプション支払総額を最小化する行使価格への引力を生む。', '「ピン」効果はディーラーガンマレジーム(EC-016)と競合するため、両者は個別ではなく併せて研究する必要がある。', '[{"kind":"internal","ref":"Deribit OI + CoinGlass","note":"満期時間帯のボラティリティ/リターン分解"}]', 'pdf_seed', 'EC-017', '{"originality":4,"feasibility":3,"verifiability":3,"lowCost":3,"dataEase":3,"durability":3,"humanOps":3}', 1782950400000, 1782950400000);

INSERT INTO edges (edge_id, slug, title, category, status, hypothesis, rationale, counter_evidence, evidence, origin, pdf_ref, priors, created_at, updated_at)
VALUES ('01KWHQ6YVRV37W1JBVKEMPSHAQ', '21-00-23-00-utc-intraday-drift', 'UTC21:00〜23:00の日中ドリフト', 'seasonality', 'IDEA', '強気相場(200日SMAより上)のレジームにおいて、BTCはUTC21:00〜23:00の時間帯で統計的に正のリターンを示す。', '米国の午後・夜間帯の流動性とフローパターンは毎日繰り返され、QuantPediaはこの時間帯のみで年率+33%のリターンを報告している。', '純粋なカレンダー効果のデータマイニングリスクは高く、2020年偏重のサンプルの外で確認し、ETF時代のフロー変化に照らして再検証する必要がある。', '[{"kind":"paper","ref":"QuantPedia: The Seasonality of Bitcoin","note":"UTC21:00〜23:00の時間帯、年率約33%"}]', 'pdf_seed', 'EC-018', '{"originality":3,"feasibility":5,"verifiability":5,"lowCost":2,"dataEase":5,"durability":3,"humanOps":5}', 1782950400000, 1782950400000);
