INSERT INTO edges (edge_id, slug, title, category, status, hypothesis, rationale, counter_evidence, evidence, origin, pdf_ref, priors, created_at, updated_at)
VALUES ('01KWHQ6YVR5164JVBPS8TQS657', 'monday-asia-open-effect', '月曜アジア開場効果', 'seasonality', 'IDEA', 'BTCは月曜UTC19:00(アジアの資金調達市場の開場)前後で、反復的な方向性の傾向を示す。', '週末の流動性の低さは、週初にアジアの機関投資家フローが戻ることで解消される。', '効果のタイミングは2020年代の研究に基づいており、市場構造が変化したETF時代以降の再検証が必要である。', '[{"kind":"paper","ref":"Concretum Group: Monday Asia Open Effect","note":"2020年代のタイミングと一致"}]', 'pdf_seed', 'EC-019', '{"originality":4,"feasibility":3,"verifiability":3,"lowCost":3,"dataEase":5,"durability":3,"humanOps":3}', 1782950400000, 1782950400000);

INSERT INTO edges (edge_id, slug, title, category, status, hypothesis, rationale, counter_evidence, evidence, origin, pdf_ref, priors, created_at, updated_at)
VALUES ('01KWHQ6YVRCHNSMH1AMHXSW7P8', 'nyse-open-day-of-week-effect', 'NYSE開場時の曜日効果', 'seasonality', 'IDEA', 'NYSE開場前後のリターンを日中区間と夜間区間に分解すると、夜間区間の比重が大きい曜日パターンが見られる。', '伝統的市場参加者のヘッジ・リバランスが、NYSE開場時に暗号資産の取引時間帯へ波及する。', '日中/夜間の分解は、境界の定義方法に敏感である。', '[{"kind":"paper","ref":"Padysak & Vojtko, paperswithbacktest","note":"NYSE開場時の夜間/日中分解"}]', 'pdf_seed', 'EC-020', '{"originality":4,"feasibility":4,"verifiability":4,"lowCost":3,"dataEase":5,"durability":3,"humanOps":4}', 1782950400000, 1782950400000);

INSERT INTO edges (edge_id, slug, title, category, status, hypothesis, rationale, counter_evidence, evidence, origin, pdf_ref, priors, created_at, updated_at)
VALUES ('01KWHQ6YVRFDG5DC9NN2RHRW74', 'cme-futures-gap-fill', 'CME先物ギャップフィル', 'seasonality', 'IDEA', 'CMEのBTC先物ギャップ(金曜引けと日曜寄りの差)は、特に小さいギャップにおいて、一定の期間内に高い確率で埋まる。', 'CMEは週5日取引だが現物は24時間365日取引されるため、このミスマッチが機械的にギャップを生み、現物/先物裁定が両者を再連結する過程でギャップが磁石のように埋まる。', '大きなギャップ(5%超)は小さなギャップ(2%未満で約92%)に比べて埋まる信頼性がはるかに低く(約52%)、ポジションサイジングはこれを考慮する必要がある。', '[{"kind":"paper","ref":"Phemex / Bitget gap-fill statistics","note":"2018〜2026年の全体的な充填率は約77%。2%未満のギャップは30日以内に約92%が充填"}]', 'pdf_seed', 'EC-021', '{"originality":3,"feasibility":5,"verifiability":5,"lowCost":4,"dataEase":4,"durability":4,"humanOps":5}', 1782950400000, 1782950400000);
INSERT INTO edge_versions (version_id, edge_id, semver, signal_spec, params, instrument_id, direction, horizon, cost_model, changelog, created_at, is_current)
VALUES ('01KWHQ6YVRNWN86SJCPKV8125B', '01KWHQ6YVRFDG5DC9NN2RHRW74', '1.0.0', '{"when":{"event":{"type":"cme_gap","min_magnitude":0}},"entry":{"delay_bars":1,"price":"open"},"exit":{"horizon":"72h"},"direction":"long"}', '{}', 'BTCUSDT.BINANCE.PERP', 'long', '72h', '{"taker_bps":4,"slippage_bps":2,"funding_included":false}', '初期PDFシードバージョン (docs/09 §3)', 1782950400000, 1);

INSERT INTO edges (edge_id, slug, title, category, status, hypothesis, rationale, counter_evidence, evidence, origin, pdf_ref, priors, created_at, updated_at)
VALUES ('01KWHQ6YVRS03P0X9TA0BWVJFA', 'month-end-rebalance-flow', '月末リバランスフロー', 'seasonality', 'IDEA', 'BTCは月末前後で、機関投資家のリバランスと整合的な反復的フローを示す。', 'インデックス連動型・マルチアセットポートフォリオは月次サイクルでリバランスするため、カレンダーに連動した反復的フローが生じる。', '他の季節性候補に比べて推測の域を出ておらず、さらなる投資の前に専用のイベントスタディが必要である。', '[{"kind":"internal","ref":"Binance daily return + calendar","note":"月末リターン分解"}]', 'pdf_seed', 'EC-022', '{"originality":2,"feasibility":4,"verifiability":4,"lowCost":3,"dataEase":5,"durability":3,"humanOps":4}', 1782950400000, 1782950400000);

INSERT INTO edges (edge_id, slug, title, category, status, hypothesis, rationale, counter_evidence, evidence, origin, pdf_ref, priors, created_at, updated_at)
VALUES ('01KWHQ6YVRVWB12C9FHM5A2N66', 'weekly-breakout-continuation', '週足ブレイクアウトの継続', 'seasonality', 'IDEA', '前週のレンジからのブレイクアウトは、平均回帰よりも継続する傾向がある。', '週足レンジは蓄積されたポジションを集約しており、真のブレイクアウトはノイズではなく実際の需給変化を反映する。', 'ブレイクアウト継続戦略はよく知られた混雑スタイルであり、エッジの持続性は不確かである。', '[{"kind":"internal","ref":"Binance weekly range breakout","note":"継続対回帰の研究"}]', 'pdf_seed', 'EC-023', '{"originality":2,"feasibility":4,"verifiability":4,"lowCost":3,"dataEase":5,"durability":2,"humanOps":4}', 1782950400000, 1782950400000);

INSERT INTO edges (edge_id, slug, title, category, status, hypothesis, rationale, counter_evidence, evidence, origin, pdf_ref, priors, created_at, updated_at)
VALUES ('01KWHQ6YVRN82D80ASMW3WCVY5', 'coinbase-premium-as-an-etf-flow-proxy', 'ETFフロー代理指標としてのCoinbaseプレミアム', 'etf_flow', 'IDEA', 'Coinbase/Binance間の価格プレミアムは米国現物ETFの純フローと相関しており、公式フローデータが公表される前のリアルタイム代理指標として機能しうる。', 'Coinbaseは米国機関投資家の主要な入り口でありETF指定参加者の取引拠点であるため、そのプレミアムは公式報告に先立つ米国の買い圧力を反映する。', 'ETFフローとの相関は中程度(R^2 ≈ 0.32)であり、単日ではこの代理指標にはノイズが多い。', '[{"kind":"internal","ref":"ainvest analysis","note":"Coinbaseプレミアム対米国ETF純フロー、R^2≈0.32"}]', 'pdf_seed', 'EC-024', '{"originality":3,"feasibility":4,"verifiability":4,"lowCost":3,"dataEase":4,"durability":3,"humanOps":4}', 1782950400000, 1782950400000);

INSERT INTO edges (edge_id, slug, title, category, status, hypothesis, rationale, counter_evidence, evidence, origin, pdf_ref, priors, created_at, updated_at)
VALUES ('01KWHQ6YVR06E3Q76X0E8SXK3X', 'etf-t-1-sell-pressure', 'ETF T+1売り圧力', 'etf_flow', 'IDEA', '大規模なETFの設定・解約は、翌取引日(T+1決済)にCoinbase Prime経由で現物の売り圧力を生む。', '指定参加者はT+1サイクルでCoinbase Prime経由でBTCを調達・処分するため、現物へのフロー影響は公式ETFフロー発表から1日遅れる。', '根拠は単一の例示的ケース(IBIT、約2,791 BTC)であり、体系的なバックテストではない。', '[{"kind":"internal","ref":"SoSoValue/ETF flow + Coinbase next-day return","note":"T+1売り圧力のケーススタディ"}]', 'pdf_seed', 'EC-025', '{"originality":4,"feasibility":3,"verifiability":3,"lowCost":3,"dataEase":3,"durability":3,"humanOps":3}', 1782950400000, 1782950400000);

INSERT INTO edges (edge_id, slug, title, category, status, hypothesis, rationale, counter_evidence, evidence, origin, pdf_ref, priors, created_at, updated_at)
VALUES ('01KWHQ6YVRJPEFR8P6ZWQG939Q', 'etf-flow-sentiment-divergence', 'ETFフロー/センチメント ダイバージェンス', 'etf_flow', 'IDEA', 'Fear & Greed指数が「恐怖」を示す一方でETF流入が継続する場合、このダイバージェンス(個人の恐怖の中で機関が蓄積する状態)は上昇に先行する。', '複数日にわたる運用方針を持つ機関投資家のETF買い手は、個人投資家より短期的なセンチメント変動に反応しにくいため、恐怖の中での継続的な買いは有益な情報となる。', 'センチメント対フローのダイバージェンスシグナルは本質的に低頻度でサンプルが限られる(ETFは2024年以降しか存在しない)。', '[{"kind":"internal","ref":"alternative.me F&G + ETF flow","note":"ダイバージェンス条件下でのフォワードリターン"}]', 'pdf_seed', 'EC-026', '{"originality":3,"feasibility":4,"verifiability":4,"lowCost":3,"dataEase":4,"durability":3,"humanOps":4}', 1782950400000, 1782950400000);

INSERT INTO edges (edge_id, slug, title, category, status, hypothesis, rationale, counter_evidence, evidence, origin, pdf_ref, priors, created_at, updated_at)
VALUES ('01KWHQ6YVRRJ515K03P77HTCB2', 'cme-cot-positioning-reversal', 'CME COTポジショニングの反転', 'etf_flow', 'IDEA', 'CFTCのCOT(トレーダーの建玉明細)における極端なネットポジション(レバレッジドファンド対アセットマネージャー)は反転に先行する。', 'レバレッジドファンドは短期的投機ポジションを表しており、十分に混雑すると強制解消リスクとなる。', 'COTデータは週次でありラグを伴って報告されるため、タイミングの精度には限界がある。', '[{"kind":"internal","ref":"CFTC COT + CoinGlass CFTC","note":"極端なポジショニングでの反転"}]', 'pdf_seed', 'EC-027', '{"originality":4,"feasibility":3,"verifiability":3,"lowCost":3,"dataEase":4,"durability":3,"humanOps":3}', 1782950400000, 1782950400000);

INSERT INTO edges (edge_id, slug, title, category, status, hypothesis, rationale, counter_evidence, evidence, origin, pdf_ref, priors, created_at, updated_at)
VALUES ('01KWHQ6YVR68HKHY18WDHW4XVA', 'exchange-netflow-signal', '取引所ネットフローシグナル', 'onchain', 'IDEA', '取引所への大きな純流入は下落(入金後の売却)に先行し、純流出は上昇(蓄積)に先行する。', '取引所へコインを移動させることは、その取引所で売却するための必要条件であるため、ネットフローは意図の先行指標となる。', '無料プランのデータでは取引所ウォレットを正確にラベル付けできず、有料プロバイダーに比べて分類精度が制限される。', '[{"kind":"internal","ref":"Glassnode (free tier) / CryptoQuant","note":"ネットフロー条件下でのフォワードリターン"}]', 'pdf_seed', 'EC-028', '{"originality":3,"feasibility":3,"verifiability":3,"lowCost":3,"dataEase":2,"durability":3,"humanOps":3}', 1782950400000, 1782950400000);

INSERT INTO edges (edge_id, slug, title, category, status, hypothesis, rationale, counter_evidence, evidence, origin, pdf_ref, priors, created_at, updated_at)
VALUES ('01KWHQ6YVR286VYPR0C8FWVGKZ', 'whale-alert-transfer-reaction', 'Whale Alert送金への反応', 'onchain', 'IDEA', '公表された大口(クジラ)送金は、市場がアラートに反応することで、短期(6〜24時間)のボラティリティ/リターンのスピルオーバーを引き起こす。', 'Whale AlertのTelegramでの広範な配信により、大口送金は送金の真の意図とは無関係に、反射的な取引反応を引き起こす共有された顕著なシグナルとなる。', 'このスピルオーバーは、送金そのものの経済的意味というより「アラートが見られたこと」への反応であり、純粋に反射的で減衰しつつある効果である可能性がある。', '[{"kind":"paper","ref":"Magner & Sanhueza 2025, Finance Research Letters","note":"スピルオーバーは1時間時点の2.78%から24時間時点の4.68%へ上昇"}]', 'pdf_seed', 'EC-029', '{"originality":4,"feasibility":3,"verifiability":3,"lowCost":3,"dataEase":3,"durability":3,"humanOps":3}', 1782950400000, 1782950400000);

INSERT INTO edges (edge_id, slug, title, category, status, hypothesis, rationale, counter_evidence, evidence, origin, pdf_ref, priors, created_at, updated_at)
VALUES ('01KWHQ6YVRJ3KYB5JNFZMPT1R6', 'exchange-whale-ratio', '取引所ホエール比率', 'onchain', 'IDEA', '上位10ウォレットの流入額が取引所全体の流入額に占める比率が高い(クジラへの集中)場合、これは分配・売却に先行する。', '大口ウォレットへの集中した入金は、広範な小口ウォレットの入金よりも、単一主体の差し迫った売却判断を表している可能性が高い。', '主張されている閾値(「85%超で売却に先行」)は独立した検証が必要であり、出典自体も逸話的なものと注記している。', '[{"kind":"internal","ref":"CryptoQuant Exchange Whale Ratio","note":"比率条件下でのフォワードリターン"}]', 'pdf_seed', 'EC-030', '{"originality":3,"feasibility":3,"verifiability":3,"lowCost":2,"dataEase":2,"durability":3,"humanOps":3}', 1782950400000, 1782950400000);

INSERT INTO edges (edge_id, slug, title, category, status, hypothesis, rationale, counter_evidence, evidence, origin, pdf_ref, priors, created_at, updated_at)
VALUES ('01KWHQ6YVRNM0Z5C6SXQ14QF0B', 'usdt-mint-event-drift', 'USDTミント(発行)イベントドリフト', 'stablecoin', 'IDEA', '大規模なUSDT Treasuryのミント(発行)イベントは、5〜30分間にわたって正のBTCドリフトを生み、60分後には減衰する。バーン(償却)には同様の効果は見られない(非対称)。', '新規ステーブルコイン発行は、取引所での新たな買付余力の前提条件である。Whale Alert経由で広く公表されたミントへのFOMO・期待反応が、純粋な流動性効果を増幅させる。', 'Griffin & Shams(2020)のTether操作仮説には、ミントが価格を動かせないとするWei(2018)の反論が公表されている。メカニズム自体に議論があるため、構造的な論拠としてではなく、短期(60分以内)のイベント効果として扱うべきである。', '[{"kind":"paper","ref":"Saggu 2022, Finance Research Letters vol.49","note":"5分時点で+0.24%、30分時点で+0.68%、60分までに減衰"}]', 'pdf_seed', 'EC-031', '{"originality":5,"feasibility":3,"verifiability":3,"lowCost":3,"dataEase":3,"durability":3,"humanOps":3}', 1782950400000, 1782950400000);
