VALUES ('01KWHQ6YVSDHM8C2VAT7ZEPY27', '01KWHQ6YVRNM0Z5C6SXQ14QF0B', '1.0.0', '{"when":{"event":{"type":"usdt_mint","min_magnitude":1000000000}},"entry":{"delay_bars":1,"price":"open"},"exit":{"horizon":"30m"},"direction":"long"}', '{}', 'BTCUSDT.BINANCE.PERP', 'long', '30m', '{"taker_bps":4,"slippage_bps":2,"funding_included":false}', '初期PDFシードバージョン (docs/09 §3)', 1782950400000, 1);

INSERT INTO edges (edge_id, slug, title, category, status, hypothesis, rationale, counter_evidence, evidence, origin, pdf_ref, priors, created_at, updated_at)
VALUES ('01KWHQ6YVSF5R19CSNV9NABF1B', 'stablecoin-supply-ratio-ssr-low-reversal', 'ステーブルコイン供給比率(SSR)低下時の反転', 'stablecoin', 'IDEA', '低いSSR(BTC時価総額に対してステーブルコインの「待機資金」が大きい状態)は、その資金が投入されることで上昇に先行する。', 'ステーブルコイン残高は、いつでも買いに転じられる待機資金を表す。BTC時価総額に対してこのプールが大きい場合、追加の買付余力は高い。', 'SSRは動きの遅いマクロ流動性指標であり、週単位より短いタイミング精度は期待しにくい。', '[{"kind":"internal","ref":"CryptoQuant / DefiLlama SSR","note":"低SSR条件下でのフォワードリターン"}]', 'pdf_seed', 'EC-032', '{"originality":3,"feasibility":4,"verifiability":4,"lowCost":3,"dataEase":4,"durability":3,"humanOps":4}', 1782950400000, 1782950400000);

INSERT INTO edges (edge_id, slug, title, category, status, hypothesis, rationale, counter_evidence, evidence, origin, pdf_ref, priors, created_at, updated_at)
VALUES ('01KWHQ6YVSWRHDSDAKKD59W7VR', 'stablecoin-issuance-acceleration', 'ステーブルコイン発行の加速', 'stablecoin', 'IDEA', 'ステーブルコイン供給総量の成長率が(単に正であるだけでなく)加速している状態は、数日〜数週間にわたるBTCへの資金流入に先行する。', '加速度(二階微分)は、水準や一階差分だけよりも明確に、資金形成の意図におけるレジーム変化を捉える。', 'DefiLlamaのステーブルコイン供給系列自体が定期的な修正を受けるため、バイテンポラル処理が必要である(docs/02 §1)。', '[{"kind":"internal","ref":"DefiLlama stablecoin supply, second derivative","note":"加速度条件下でのフォワードリターン"}]', 'pdf_seed', 'EC-033', '{"originality":3,"feasibility":4,"verifiability":4,"lowCost":3,"dataEase":4,"durability":3,"humanOps":4}', 1782950400000, 1782950400000);

INSERT INTO edges (edge_id, slug, title, category, status, hypothesis, rationale, counter_evidence, evidence, origin, pdf_ref, priors, created_at, updated_at)
VALUES ('01KWHQ6YVSWJWV9Q8RNYTVWK14', 'usdt-depeg-risk-off-signal', 'USDTデペッグ時のリスクオフシグナル', 'stablecoin', 'IDEA', 'USDTが1ドルを大きく下回って取引される(デペッグ)状態は、資金がステーブルコイン全体から広く逃避する(BTCへではなく暗号資産全体からの安全資産への逃避)ことで、BTCの下落に先行する。', 'ステーブルコインのデペッグは、暗号資産市場インフラにおけるシステミック・カウンターパーティストレスを示すシグナルであり、資産の乗り換えではなく広範なリスク削減を促す。', 'デペッグ事象は稀であり、それぞれ固有の原因を持つ(2023年の銀行セクター伝播など)ため、事象間での一般化は証明されていない。', '[{"kind":"internal","ref":"Binance USDT/USDC + CoinGecko","note":"デペッグイベント時のフォワードリターン"}]', 'pdf_seed', 'EC-034', '{"originality":3,"feasibility":4,"verifiability":3,"lowCost":3,"dataEase":4,"durability":2,"humanOps":4}', 1782950400000, 1782950400000);

INSERT INTO edges (edge_id, slug, title, category, status, hypothesis, rationale, counter_evidence, evidence, origin, pdf_ref, priors, created_at, updated_at)
VALUES ('01KWHQ6YVSE8HB7Z339A4YZ93A', 'nasdaq-cross-asset-regime-linkage', 'Nasdaqとのクロスアセットレジーム連動', 'cross_asset', 'IDEA', 'BTC-Nasdaqの相関はリスクオフ局面で強まる。生の相関そのものではなく、相関のレジーム自体が有益な情報となる。', 'ETF保有が拡大するにつれ、BTCはストレス時に高ベータのマクロリスク資産として取引される傾向が強まり、株式との連動が強まっている。', 'チョウ検定はETF承認前後で構造変化を検出しており、前後の関係を単純にプールすることはできない。', '[{"kind":"paper","ref":"arXiv:2512.12815","note":"チョウ検定による構造変化、BTC-S&P500間、p=0.0000"}]', 'pdf_seed', 'EC-035', '{"originality":3,"feasibility":3,"verifiability":3,"lowCost":3,"dataEase":4,"durability":3,"humanOps":3}', 1782950400000, 1782950400000);

INSERT INTO edges (edge_id, slug, title, category, status, hypothesis, rationale, counter_evidence, evidence, origin, pdf_ref, priors, created_at, updated_at)
VALUES ('01KWHQ6YVSKDN6C253ER5Q5NSC', 'dxy-correlation-regime', 'DXY(ドル指数)相関レジーム', 'cross_asset', 'IDEA', 'BTC/DXYの相関はレジーム依存であり、レジームが安定して負である間のみ方向性判断に有益である。', 'ドルの強弱は標準的なマクロ流動性の代理指標だが、BTCとの連動性はその時々の支配的なマクロナラティブによって強弱が変化する。', 'JPMorgan(2026年)によれば、相関は2014〜2020年の約0.7から最近では約0.45へ低下しており、レジーム条件付けなしでの利用は不安定である。', '[{"kind":"internal","ref":"FRED DXY + Binance, OSL / JPMorgan commentary","note":"相関レジームの変化"}]', 'pdf_seed', 'EC-036', '{"originality":2,"feasibility":3,"verifiability":3,"lowCost":2,"dataEase":4,"durability":2,"humanOps":3}', 1782950400000, 1782950400000);

INSERT INTO edges (edge_id, slug, title, category, status, hypothesis, rationale, counter_evidence, evidence, origin, pdf_ref, priors, created_at, updated_at)
VALUES ('01KWHQ6YVSYCACKJSF9N1EJ35J', 'global-m2-liquidity-linkage', 'グローバルM2流動性との連動', 'cross_asset', 'IDEA', 'グローバルM2マネーサプライの変化は、流動性主導型リスク資産としてのBTC価格に対し、数週間のラグを伴って先行する。', 'BTCは流動性に敏感な長期デュレーションのリスク資産として振る舞うため、他のリスク資産と同様に、総体的なマネーサプライの拡大・縮小がBTCに先行するはずである。', 'M2データは低頻度(月次)であり修正も入るため、単独シグナルとしてではなく動きの遅い条件変数としてのみ有用である。', '[{"kind":"internal","ref":"FRED M2 + TradingEconomics + Binance","note":"ラグを伴うM2-BTC関係"}]', 'pdf_seed', 'EC-037', '{"originality":3,"feasibility":3,"verifiability":2,"lowCost":2,"dataEase":4,"durability":3,"humanOps":3}', 1782950400000, 1782950400000);

INSERT INTO edges (edge_id, slug, title, category, status, hypothesis, rationale, counter_evidence, evidence, origin, pdf_ref, priors, created_at, updated_at)
VALUES ('01KWHQ6YVTQ6SX1BZGND4KWB3G', 'round-number-price-clustering', 'ラウンドナンバーへの価格クラスタリング', 'behavioral', 'IDEA', '価格はアンカリングとストップ・指値の配置により、1,000ドル刻みのラウンドナンバーに集中するが、ラウンドナンバーに到達した後のリターンには有意なパターンは見られない。', 'アンカリングバイアス(Harris 1991年型のラウンドナンバー効果)により、注文がラウンドレベルに集中して配置される。', '元論文は、ラウンドナンバー到達後に有意なリターンパターンがないことを明示的に示している。クラスタリング自体は実在するが、記載どおりには直接取引可能ではない。', '[{"kind":"paper","ref":"Urquhart 2017, Economics Letters vol.159","note":"Bitstampの価格の10.81%が「00」で終わる。到達後の有意なリターンパターンはなし"}]', 'pdf_seed', 'EC-038', '{"originality":4,"feasibility":3,"verifiability":3,"lowCost":3,"dataEase":4,"durability":3,"humanOps":3}', 1782950400000, 1782950400000);

INSERT INTO edges (edge_id, slug, title, category, status, hypothesis, rationale, counter_evidence, evidence, origin, pdf_ref, priors, created_at, updated_at)
VALUES ('01KWHQ6YVTZJADX51JTNYEGW01', 'price-momentum-continuation', '価格モメンタムの継続', 'behavioral', 'IDEA', '直近数日〜週次のモメンタムは、注目度やFOMO・ショートカバーの力学に駆動され、反転よりも継続する傾向がある。', '注目度の上昇はさらなる注目(メディア、SNS、検索)を生み、それがさらなる買いを生むという、ファンダメンタルズとは異なる反射的なモメンタムループである。', 'モメンタムは金融全体で最も広く利用されているスタイルの一つであり、混雑リスクが高く持続性は不確かである。', '[{"kind":"internal","ref":"Binance daily/weekly momentum","note":"継続条件下でのフォワードリターン"}]', 'pdf_seed', 'EC-039', '{"originality":2,"feasibility":4,"verifiability":4,"lowCost":3,"dataEase":5,"durability":3,"humanOps":4}', 1782950400000, 1782950400000);

INSERT INTO edges (edge_id, slug, title, category, status, hypothesis, rationale, counter_evidence, evidence, origin, pdf_ref, priors, created_at, updated_at)
VALUES ('01KWHQ6YVTJJ1D8429KH761MYA', 'google-trends-overheat-fomo-fade', 'Googleトレンド過熱/FOMOのフェード', 'behavioral', 'IDEA', '「Bitcoin」の検索量の急上昇は個人投資家のFOMOを示し、局所的な天井/押し目に先行する。', '個人投資家の検索関心は、メディア報道や口コミによる注目が実際の値動きに遅れることで、陶酔的な天井付近でピークを迎える。', '先行研究(arXiv:1408.1494)では検索急増が「下落」に先行するとされているが、因果の方向性(検索が価格を引き起こすのか、価格が検索を引き起こすのか)は未解明である。', '[{"kind":"paper","ref":"arXiv:1408.1494","note":"検索量の急増は価格下落に先行する"}]', 'pdf_seed', 'EC-040', '{"originality":3,"feasibility":3,"verifiability":3,"lowCost":2,"dataEase":4,"durability":2,"humanOps":3}', 1782950400000, 1782950400000);

INSERT INTO edges (edge_id, slug, title, category, status, hypothesis, rationale, counter_evidence, evidence, origin, pdf_ref, priors, created_at, updated_at)
VALUES ('01KWHQ6YVT2R9FZGZBDA9KJ6QM', 'pre-fomc-drift', 'FOMC前ドリフト', 'event', 'IDEA', 'BTCはFOMC発表の前日に上昇し、発表当日には下落する。', '株式市場で報告されている発表前リスクプレミアム/情報漏洩の力学(Cieslak, Morse & Vissing-Jorgensen 2019)が、よりマクロ連動性を強めたBTCの挙動にも及んでいる。', '効果量(前日約+0.96%、発表当日約-1%)は、BTCの通常の日次ボラティリティに対して控えめである。', '[{"kind":"paper","ref":"Pyo & Lee 2020, Finance Research Letters vol.37","note":"前日+0.96%、発表当日-1%"}]', 'pdf_seed', 'EC-041', '{"originality":3,"feasibility":4,"verifiability":4,"lowCost":3,"dataEase":5,"durability":3,"humanOps":4}', 1782950400000, 1782950400000);

INSERT INTO edges (edge_id, slug, title, category, status, hypothesis, rationale, counter_evidence, evidence, origin, pdf_ref, priors, created_at, updated_at)
VALUES ('01KWHQ6YVTTGM77H1CZESBTZZY', 'sell-the-news-fomc-drift', '「セル・ザ・ニュース」FOMCドリフト', 'event', 'IDEA', 'BTCは、実際の決定内容に関わらず、FOMC発表後48時間で下落する傾向がある。', '事前に構築された期待(「噂で買う」)は、ニュース自体がタカ派かハト派かに関わらず、イベント通過後に機械的に解消される。', '根拠として引用されている(2025年のFOMC会合8回中7回)は、単一の二次情報源による小規模で直近偏重のサンプルであり、独立して再現された研究ではない。', '[{"kind":"internal","ref":"Coinmonks analysis","note":"2025年のFOMC会合8回中7回で発表後の下落が見られた"}]', 'pdf_seed', 'EC-042', '{"originality":3,"feasibility":4,"verifiability":4,"lowCost":2,"dataEase":5,"durability":2,"humanOps":4}', 1782950400000, 1782950400000);

INSERT INTO edges (edge_id, slug, title, category, status, hypothesis, rationale, counter_evidence, evidence, origin, pdf_ref, priors, created_at, updated_at)
VALUES ('01KWHQ6YVTMPCX41EFP9QVDXC5', 'cpi-macro-print-volatility-compression', 'CPI/マクロ指標発表前のボラティリティ収縮', 'event', 'IDEA', 'BTCの実現ボラティリティは主要マクロ指標発表(CPI、PPI、FOMC)前に収縮し、発表後に拡大する。', '指標発表前のポジション調整における慎重さが実際の値動きを抑制し、発表による不確実性の解消が抑圧されていたボラティリティを解放する。', 'BTCのボラティリティが有意に反応するのは、検証された29のマクロ指標のうち約10個のみであり、大半の発表では測定可能な効果は見られない。', '[{"kind":"paper","ref":"ScienceDirect S1059056025006720","note":"検証された29指標のうちCPI/PPI/FOMCで有意なボラティリティ反応"}]', 'pdf_seed', 'EC-043', '{"originality":3,"feasibility":3,"verifiability":3,"lowCost":3,"dataEase":4,"durability":3,"humanOps":3}', 1782950400000, 1782950400000);

INSERT INTO edges (edge_id, slug, title, category, status, hypothesis, rationale, counter_evidence, evidence, origin, pdf_ref, priors, created_at, updated_at)
VALUES ('01KWHQ6YVTD1AHQZKYAPPDY1WQ', 'altcoin-sideways-breakout-drift-btc-pair', 'アルトコインのレンジブレイクアウトドリフト(BTC建て)', 'event', 'IDEA', '主要アルトコイン/BTCペアにおけるレンジブレイクアウトは、BTC建てフローに関連する反復的な統計パターンを示す。', 'BTCとアルトコイン間の注目度・流動性のローテーションは、相対強度ブレイクアウトに結びついた反復的な循環パターンに従う。', 'この候補群の中で最も検討が進んでいないものであり、さらなる投資の前に専用のイベントスタディが必要である。', '[{"kind":"internal","ref":"exchange-provided BTC-pair data","note":"ブレイクアウト条件下でのフォワードリターン"}]', 'pdf_seed', 'EC-044', '{"originality":2,"feasibility":3,"verifiability":3,"lowCost":3,"dataEase":3,"durability":2,"humanOps":3}', 1782950400000, 1782950400000);

INSERT INTO edges (edge_id, slug, title, category, status, hypothesis, rationale, counter_evidence, evidence, origin, pdf_ref, priors, created_at, updated_at)
VALUES ('01KWHQ6YVT39NZE44RCJC9HSA4', 'garch-volatility-regime-clustering', 'GARCHによるボラティリティレジームクラスタリング', 'vol_regime', 'IDEA', 'BTCのボラティリティは強いGARCHクラスタリング(alpha+beta ≈ 0.90)を示すため、レジームの持続性そのものが取引可能・条件付け可能なシグナルとなる。', 'ボラティリティクラスタリングは持続的な情報フローとポジションサイジングのフィードバックを反映しており、一度上昇すると高止まりする傾向がある。', '高い持続性(alpha+betaが1に近い)はほぼ単位根的な分散を示唆し、クラスタリングそのものよりも、レジーム転換のタイミングを捉えることの方がより難しく未解決の課題となる。', '[{"kind":"paper","ref":"SSRN 5611392","note":"GARCH alpha+beta ≈ 0.90 の持続性"},{"kind":"paper","ref":"Takaishi 2021, PLOS ONE","note":"レジーム転換型GARCH"}]', 'pdf_seed', 'EC-045', '{"originality":3,"feasibility":3,"verifiability":3,"lowCost":3,"dataEase":5,"durability":4,"humanOps":3}', 1782950400000, 1782950400000);

INSERT INTO edges (edge_id, slug, title, category, status, hypothesis, rationale, counter_evidence, evidence, origin, pdf_ref, priors, created_at, updated_at)
VALUES ('01KWHQ6YVTARFA86V5X7HZBKNR', 'inverted-leverage-effect-btc-vol-asymmetry', '逆転したレバレッジ効果(BTCボラティリティの非対称性)', 'vol_regime', 'IDEA', '株式とは異なり、BTCのボラティリティは負のリターンよりも正のリターンに対してより強く反応する(逆転した非対称性)。', '暗号資産では買い側のFOMO・モメンタム追随の力学が、株式型のレバレッジ効果(負のリターンがボラティリティをより高める)より優勢である。', 'この効果は、より小規模だった過去のBTC市場で報告されたものであり、より機関投資家主導となった現在の市場構造での再検証が必要である。', '[{"kind":"paper","ref":"Takaishi 2021, PLOS ONE","note":"逆転した非対称性:ボラティリティは正のリターンにより強く反応"}]', 'pdf_seed', 'EC-046', '{"originality":4,"feasibility":3,"verifiability":3,"lowCost":3,"dataEase":5,"durability":3,"humanOps":3}', 1782950400000, 1782950400000);

INSERT INTO edges (edge_id, slug, title, category, status, hypothesis, rationale, counter_evidence, evidence, origin, pdf_ref, priors, created_at, updated_at)
VALUES ('01KWHQ6YVTGFFR7WVSEWTQD1H1', 'jump-dynamics-via-lee-mykland-detection', 'Lee-Mykland検出によるジャンプダイナミクス', 'vol_regime', 'IDEA', '統計的に検出された価格ジャンプ(Lee-Myklandテスト)は、オーダーフローインバランスの極値と共起する。すなわちジャンプは一部が情報主導、一部が流動性主導である。', 'ジャンプは真の情報ショックか流動性のエアポケットのいずれかを反映しており、OFIの文脈でこの両者を区別できれば、ジャンプリスクを部分的に予測可能にできる可能性がある。', '過去の例示的ケース(Mt. Gox)は極端で代表性のないテールイベントである。', '[{"kind":"internal","ref":"Lee-Mykland jump detection + Binance","note":"ジャンプ/OFI共起"}]', 'pdf_seed', 'EC-047', '{"originality":3,"feasibility":3,"verifiability":3,"lowCost":3,"dataEase":4,"durability":3,"humanOps":3}', 1782950400000, 1782950400000);

INSERT INTO edges (edge_id, slug, title, category, status, hypothesis, rationale, counter_evidence, evidence, origin, pdf_ref, priors, created_at, updated_at)
VALUES ('01KWHQ6YVVD13RNXRKX29EZKHF', 'session-open-close-volatility-seasonality', 'セッション開場/閉場時のボラティリティ季節性', 'vol_regime', 'IDEA', '5分足の実現ボラティリティは、米国株式セッションの開場/閉場にあたるEST12:00前後でピークを迎え、伝統的市場のセッション境界に追随する。', '24時間365日の暗号資産市場においても、多くの流動性が米国時間帯のデスクに由来するため、伝統的市場のセッション境界に機関投資家の注文フローが集中する。', 'この候補群の中で最も頑健な効果の一つ(持続性4、検証可能性4)だが、単独での取引価値は限定的である(方向性ではなくボラティリティのタイミングのみ)。', '[{"kind":"paper","ref":"ScienceDirect S1059056025006720","note":"5分足ボラティリティはEST12:00のセッション開場/閉場でピーク"}]', 'pdf_seed', 'EC-048', '{"originality":2,"feasibility":4,"verifiability":4,"lowCost":4,"dataEase":5,"durability":4,"humanOps":4}', 1782950400000, 1782950400000);

INSERT INTO edges (edge_id, slug, title, category, status, hypothesis, rationale, counter_evidence, evidence, origin, pdf_ref, priors, created_at, updated_at)
VALUES ('01KWHQ6YVVXGTE75VG0KEJJWQJ', 'perp-spot-volume-ratio-leverage-regime', '無期限先物/現物出来高比率レバレッジレジーム', 'cross_venue', 'IDEA', '無期限先物/現物の出来高比率が高いことは、急激な反転が起きやすいレバレッジ主導(脆弱)な市場を示すシグナルとなる。', 'デリバティブの出来高が現物を圧倒する場合、価格発見は現金主導ではなくレバレッジ主導となり、強制デレバレッジによる反転のリスクが高まる。', 'Bybitの無期限先物シェアは構造的に既に非常に高い(通常約92.5%)状態にあるため、「高い比率」の閾値は取引所ごとに慎重な調整が必要である。', '[{"kind":"internal","ref":"CCN / Kapar & Olmo","note":"無期限先物/現物比率は通常60〜80%の範囲"}]', 'pdf_seed', 'EC-049', '{"originality":4,"feasibility":3,"verifiability":3,"lowCost":3,"dataEase":4,"durability":3,"humanOps":3}', 1782950400000, 1782950400000);

INSERT INTO edges (edge_id, slug, title, category, status, hypothesis, rationale, counter_evidence, evidence, origin, pdf_ref, priors, created_at, updated_at)
VALUES ('01KWHQ6YVVD995N0EWQNJPN961', 'cross-exchange-funding-divergence', '取引所間の資金調達率ダイバージェンス', 'cross_venue', 'IDEA', 'Binance/Bybit/OKX/Hyperliquid間で持続する資金調達率のダイバージェンスは、構造的で取引所固有のポジション不均衡に関する有益な情報となる。', '取引所ごとに異なるトレーダー層(個人対プロ、地域拠点)を惹きつけるため、持続的なダイバージェンスは単なるノイズではなく実際のセグメンテーションを反映する。', '引用されている業界の見解では、こうしたダイバージェンスは「裁定可能な価格の歪みというより、構造的な設計の違いを反映することが多い」とされており、単独の裁定機会としてではなく条件変数として扱うべきである。', '[{"kind":"internal","ref":"MetaMask commentary + exchange funding APIs","note":"取引所間の資金調達率ダイバージェンス"}]', 'pdf_seed', 'EC-050', '{"originality":3,"feasibility":3,"verifiability":3,"lowCost":3,"dataEase":4,"durability":2,"humanOps":3}', 1782950400000, 1782950400000);

INSERT INTO edges (edge_id, slug, title, category, status, hypothesis, rationale, counter_evidence, evidence, origin, pdf_ref, priors, created_at, updated_at)
VALUES ('01KWHQ6YVVY1ZVY7KBFNCEM9J9', 'hyperliquid-on-chain-positioning-transparency', 'Hyperliquidのオンチェーンポジション透明性', 'cross_venue', 'IDEA', 'Hyperliquidの完全オンチェーンの板・ポジションデータ(CEXでは入手不可)は、総体的なポジショニングに関する情報優位性を与える。', 'L1上の板における完全な取引・ポジションの透明性は、主要デリバティブ取引所の中で構造的に特異である。', 'Hyperliquidは比較的新しく規模の小さい取引所であり、そのポジショニングがより広い市場構造に一般化できるかは証明されていない。', '[{"kind":"internal","ref":"coinmarketman + Hyperliquid public API","note":"オンチェーンポジション分布の追跡"}]', 'pdf_seed', 'EC-051', '{"originality":5,"feasibility":3,"verifiability":3,"lowCost":3,"dataEase":4,"durability":3,"humanOps":3}', 1782950400000, 1782950400000);

INSERT INTO edges (edge_id, slug, title, category, status, hypothesis, rationale, counter_evidence, evidence, origin, pdf_ref, priors, created_at, updated_at)
VALUES ('01KWHQ6YVVN39CDZZYD8AV3WDM', 'kimchi-premium-korea-exchange-spread', 'キムチプレミアム(韓国取引所スプレッド)', 'cross_venue', 'IDEA', 'Upbit/Bithumbとグローバル取引所間の価格プレミアム(「キムチプレミアム」)は、韓国個人投資家のセンチメントと資本規制による摩擦を反映する。', '韓国ウォンの資本規制により摩擦のない裁定取引ができないため、このプレミアムは持続的で地域的に分断された個人センチメントの指標となる。', 'KRW/USDの換算により、このシグナルには為替タイミングへの依存性が加わる。', '[{"kind":"internal","ref":"Upbit/Bithumb + Binance + FRED KRW/USD","note":"プレミアム条件下でのフォワードリターン"}]', 'pdf_seed', 'EC-052', '{"originality":3,"feasibility":3,"verifiability":3,"lowCost":3,"dataEase":3,"durability":2,"humanOps":3}', 1782950400000, 1782950400000);

INSERT INTO edges (edge_id, slug, title, category, status, hypothesis, rationale, counter_evidence, evidence, origin, pdf_ref, priors, created_at, updated_at)
VALUES ('01KWHQ6YVVDZ87W8YVT9GBH197', 'regional-cex-flow-divergence-coinbase-vs-binance', '地域別CEXフローダイバージェンス(Coinbase対Binance)', 'cross_venue', 'IDEA', 'Coinbase主導の値動き(米国時間帯)とBinance主導の値動き(グローバル/アジア時間帯)は、体系的に異なるフォロースルー特性を持つ。', '地域的フローは異なるトレーダー層(Coinbase経由の米国機関投資家対Binance経由のグローバル個人・レバレッジ)に由来し、持続性が異なる。', '「どの取引所が主導したか」の判定自体が、使用するリード・ラグの時間窓に敏感なモデリング上の選択である。', '[{"kind":"internal","ref":"cross-exchange aggTrades","note":"主導取引所条件下でのフォワードリターン"}]', 'pdf_seed', 'EC-053', '{"originality":4,"feasibility":3,"verifiability":3,"lowCost":3,"dataEase":3,"durability":3,"humanOps":3}', 1782950400000, 1782950400000);

INSERT INTO edges (edge_id, slug, title, category, status, hypothesis, rationale, counter_evidence, evidence, origin, pdf_ref, priors, created_at, updated_at)
VALUES ('01KWHQ6YVVV50RRENG1E4EE0T9', 'eth-cross-sectional-feature-transfer-from-btc', 'BTCからETHへのクロスセクショナル特徴量の転移', 'cross_venue', 'IDEA', 'BTCで学習したマイクロストラクチャー特徴量(OFI等)はETHや他の大型銘柄にも転移し、スケール不変なマイクロストラクチャーメカニズムを示唆する。', 'オーダーフローインバランスの力学がBTC特有のものではなく中央集権型指値注文板の構造的特徴であるならば、同じ特徴量ランキング/SHAP重要度が銘柄を超えて成立するはずである。', '元研究のクロスアセットセット(BTC、LTC、ETC、ENJ、ROSE)は流動性の面で異質であり、ETH固有の一般化には直接的な検証がまだ必要である。', '[{"kind":"paper","ref":"arXiv:2602.00776","note":"特徴量ランキング/SHAPはBTC、LTC、ETC、ENJ、ROSEにわたって安定"}]', 'pdf_seed', 'EC-054', '{"originality":4,"feasibility":3,"verifiability":3,"lowCost":4,"dataEase":4,"durability":4,"humanOps":3}', 1782950400000, 1782950400000);

